import numpy as np

def random_init(n_params):
    return np.random.randn(n_params)

def structured_init(n_params):
    params = []
    for i in range(n_params):
        # Decay scale with parameter index
        scale = 1.0 / (i + 1)
        params.append(np.random.randn() * scale * 0.1)
    return np.array(params)

def classical_guided_init(classical_weights):
    return 2 * np.arctan(classical_weights * 0.5)

def estimate_gradient_magnitude(params, quantum_fn, x, eps=0.01):
    grad = np.zeros_like(params)
    base_output = quantum_fn(params, x)

    for i in range(len(params)):
        params_plus = params.copy()
        params_plus[i] += eps
        output_plus = quantum_fn(params_plus, x)
        grad[i] = (output_plus - base_output) / eps

    return np.linalg.norm(grad)

# Test
np.random.seed(42)
print("Barren Plateau Comparison:")
print("=" * 40)

def quantum_fn(params, x):
    result = x
    for p in params:
        result = np.sin(p * result)
    return result

n_params = 8
classical = np.random.randn(n_params)

# Different initializations
initializations = {
    'Random': random_init(n_params),
    'Structured': structured_init(n_params),
    'Classical-guided': classical_guided_init(classical)
}

print("\nInitialization comparison:")
for name, params in initializations.items():
    grad_mag = estimate_gradient_magnitude(params, quantum_fn, 0.5)
    param_mag = np.linalg.norm(params)
    print(f"  {name:18}: |params|={param_mag:.3f}, |grad|={grad_mag:.4f}")

# Compare across multiple samples
print("\nAverage gradient magnitude (10 trials):")
for name in ['Random', 'Structured', 'Classical-guided']:
    mags = []
    for _ in range(10):
        if name == 'Random':
            params = random_init(n_params)
        elif name == 'Structured':
            params = structured_init(n_params)
        else:
            params = classical_guided_init(np.random.randn(n_params))
        mags.append(estimate_gradient_magnitude(params, quantum_fn, 0.5))
    print(f"  {name:18}: {np.mean(mags):.4f} ± {np.std(mags):.4f}")
